INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (6, '[{"questions": [{"type": "text", "label": "Nom", "value": "GIROT"}, {"type": "text", "label": "Prénom", "value": "Dewi"}, {"type": "email", "label": "Email", "value": "girotd@3il.fr"}, {"type": "checkbox", "label": "En cochant cette case, j'accepte d'être contacté(e) par des étudiants pour partager des informations et des retours d'expérience.", "value": "Non"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "22"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Taïwan"}, {"type": "text", "label": "Ville", "value": "Hualien"}, {"type": "text", "label": "Établissement d'accueil", "value": "NDHU"}, {"type": "select-one", "label": "Type de programme", "value": "Echange bilatéral"}, {"type": "date", "label": "Date de début", "value": "2024-09-06"}, {"type": "date", "label": "Date de fin", "value": "2025-01-03"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1200"}, {"type": "select-one", "label": "Langue d'enseignement", "value": "Anglais"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "Le temps de la mobilité donc minimum 6 mois. Il faut un visa pour y aller donc le temps d'avoir le visa, je dirais que minimum 1 an est confortable voir nécessaire le temps des démarches si l'on veut s'y prendre à l'avance."}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Oui", "details": "Visa \"visitor\" nécessaire et la demande est à faire 3 mois à l'avance (il périme si l'on ne rentre pas sur le territoire dans les 3 mois après sa création)"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y'a-t-il des vaccinations obligatoires ?", "value": "Oui", "details": "Rubella, rougeole et tétanos il me semble. A vérifier avec le gouvernement et l'université chaque année."}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Prévenir la banque de votre mobilité. Dans mon cas, j'ai souscrit pour une carte avec un nombre de retraits illimités et sans frais puisque la majorité des transactions se font par cash à Taiwan."}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d'apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d'aides financières ?", "value": "Oui", "details": "Aide européenne et régionales"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Oui", "details": "Assurance (Chapka) pour le voyage"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Compris dans mon assurance (Chapka)"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d'Ariane)?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Chongwa telecom, environ 60€ pour 4 mois avec données illimités"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Topics and optimization making"}, "Avis du cours": {"type": "textarea", "value": "Cours complexe au début mais les évaluations sont \"simples\""}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Fuzzy method pour la résolution de problèmes complexes"}}, {"Nom du cours": {"type": "text", "value": "Wireless internet"}, "Avis du cours": {"type": "textarea", "value": "Intéressant mais il ne faut pas se laisser distraire et rester focus. Bonus: 1h30 de cours par semaine."}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours de réseau mais le professeur à un petit accent donc facile de s'y perdre et surtout, l'évaluation est compliquée. Le système est celui d'une université donc complètement différent de 3IL"}}, {"Nom du cours": {"type": "text", "value": "Fondamental Chinese"}, "Avis du cours": {"type": "textarea", "value": "Super intéressant et pas très compliqué si vous vous y intéressez un peu"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Etude de la langue"}}, {"Nom du cours": {"type": "text", "value": "IOT"}, "Avis du cours": {"type": "textarea", "value": "Professeur jeune et compétent. Seulement des travaux pratiques et le cours est intéressant puisque vous manipulez."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Réalisation de projets en IOT"}}, {"Nom du cours": {"type": "text", "value": "Theory of computer games"}, "Avis du cours": {"type": "textarea", "value": "Cours intéressant et professeur compréhensible."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Logique et apprentissage de problèmes à travers la résolutions de jeux (jeu de Go)"}}, {"Nom du cours": {"type": "text", "value": "Strategy management of technology"}, "Avis du cours": {"type": "textarea", "value": "Intéressant mais cela ne se concentre que sur l'élaboration de Business Plan donc avec 3IL, vous aurez beaucoup d'acquis."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Apprendre les stratégies de management"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l'enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "18"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d'intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d'intégration avec les étudiants locaux et internationaux", "value": "5", "details": "Vous logerez sur un campus universitaire (ou du moins je vous le conseille fortement) et vous y rencontrerez beaucoup d'étudiants de partout dans le monde.", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d'accueil pour les étudiants étrangers", "value": "Oui", "details": "Intégration à travers des soirées"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Oui", "details": "Clubs de sports (kickboxing, natation, musculation)"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "5", "details": "Incroyable", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d'intégration pour les futurs étudiants", "value": "N'hésitez pas à aller parler aux gens, ils sont super curieux sur les européens"}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l'accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Population super accueillante et bienveillante", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Cérémonies, marchés et événements."}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Tout est différent donc très dépaysant et intéressant"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "details": "Très facile et vous vous adapterez rapidement", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Je ne peux pas les énumérés, il y en a trop..."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Oui", "details": "Il faut avoir du respect pour les autres puisque tous vos repères vont changer et ne portez pas de jugements sur les autres (sinon choisissez un pays européen)"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Si vous n'êtes pas très à être ouverts à la nouveauté, changer vos habitudes ou bien que vous aimez bien vos routines européennes, je vous conseille de plutôt rester en Europe puisqu'ici, tous vos repères changeront."}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Musées et parler avec des habitants"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "80"}, {"type": "select-one", "label": "Type de logement", "value": "Résidence universitaire"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "5", "details": "Le logement vous est proposé lors de votre inscription (n'oubliez pas de le demander)", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Incroyable rapport qualité/prix"}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "Vous devrez acheter beaucoup de fournitures mais ce n'est pas cher.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "details": "Vous devrez acheter un vélo pour 30€, c'est indispensable (le campus est trop grand pour le faire à pied)", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "details": "Rue commerçante à la sortie du campus, à 5 min en vélo", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Sécurité maximale, beaucoup d'étudiants ne ferment même pas leurs chambres à clés.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Habitez sur le campus !"}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "500", "details": "Tout dépend de vos habitudes et si vous souhaitez beaucoup voyager et si oui, où."}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Très bas"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Un repas en restaurant coûte maximum 3€ et vous mangerez tout le temps dehors puisque c'est la culture ici."}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Très bas"}, {"type": "textarea", "label": "Suggestions d'activités abordables ou gratuites", "value": "12€ pour l'inscription dans le club de kickboxing et les clubs les plus cher sont à 60€ pour l'années donc ce n'est vraiment pas grand chose en sachant que pour la plupart des sports, vous pourrez les pratiquer sans avoir besoin d'être dans un club (exemple: volleyball en extérieur)"}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Très bas"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "60€ pour 4 mois avec data illimités (15€/mois)"}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Très bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Transport très très peu cher et super efficace"}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d'origine", "value": "Très bas"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Besoin de faire une liste des tâches administratives à faire en ville/université lors de l'arrivée sur le campus"}, {"type": "textarea", "label": "Impact de l'expérience sur vos perspectives académiques et personnelles", "value": "Ouverture d'esprit"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Tout était incroyable"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "Soyez attentifs un minimum en cours et n'en séchez pas trop"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d'autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-26', 'NDHU', 2024, 'Hualien', 'Taïwan', 'alternant', false, null, null, null);
