INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (16, '[{"questions": [{"type": "text", "label": "Nom", "value": "Vogel"}, {"type": "text", "label": "Prénom", "value": "Lucas"}, {"type": "email", "label": "Email", "value": "lucas.vogel007@hotmail.fr"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "22"}, {"type": "select-one", "label": "Campus 3iL", "value": "Limoges"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Estonie"}, {"type": "text", "label": "Ville", "value": "Tartu"}, {"type": "text", "label": "Établissement d''accueil", "value": "University of Tartu"}, {"type": "select-one", "label": "Type de programme", "value": "Erasmus"}, {"type": "date", "label": "Date de début", "value": "2024-08-26"}, {"type": "date", "label": "Date de fin", "value": "2025-02-02"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Voiture"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Anglais"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Non"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Prévenir la banque du déplacement en Estonie"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "Aides Erasmus"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Oui", "details": "Oui, je suis allé au poste de police pour me faire faire une carte d''identité temporaire. (Il vaut mieux réserver un créneau sur leur site pour le premier rdv et aussi un pour la récupérer car il y a beaucoup de monde)"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Non"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Devops: Automating Software Delivery and Operations"}, "Avis du cours": {"type": "textarea", "value": "Le cours était très intéressant et pertinent pour le monde professionnel."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours concernant la structure d''un projet, plus spécifiquement son suivi avec gitlab accompagnés de TP (aussi avec du docker etc...)"}}, {"Nom du cours": {"type": "text", "value": "Design And Analysis of Algorithms"}, "Avis du cours": {"type": "textarea", "value": "Le cours est compliqué et demande beaucoup de temps personnel."}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Mathématiques centrés sur la théorie des graphes et des algorithmes liés à ce domaine.\\n6 devoirs maisons assez lourd à faire durant le semestre."}}, {"Nom du cours": {"type": "text", "value": "Coding theory"}, "Avis du cours": {"type": "textarea", "value": "Encore une fois un cours assez compliqué mais l''enseignante est très gentille et n''hésite pas à reexpliquer les conceptes que l''on ne comprend pas."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours portant sur l''encodage des donnés. On y voit les algorithmes permettant de réduire au maximum les pertes de donnés. Il y a une évaluation (où on peut emmener les notes papier) et 6 devoirs maison qui suivent de près le cours."}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "15"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "3", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Oui", "details": "Beaucoup de travail maison à faire"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Cérémonie d''accueil pour les étudiants, et autres activités faites par Erasmus (esn)"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "N''hésitez pas à utiliser le chat whatsapp des étudiants erasmus de Tartu"}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Non"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Le plat de Noël, qui contient du boudin noir, des salades, du chorizo, du pain noir et encore d''autres choses."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Oui", "details": "La politesse se fait plus timide chez les Estoniens."}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": null}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "260"}, {"type": "select-one", "label": "Type de logement", "value": "Résidence universitaire"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "5", "details": "Le logement était recommendé par l''école.", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Le prix est assez correcte par rapport aux autres appartements disponibles."}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "4", "details": "Immeuble assez ancien, donc matériel bien usé.", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "4", "details": "Pour un appartement, il y a 3 chambres de 2 personnes, une cuisine en commun, une salle de bain avec douche et un wc.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "details": "Arrêt de bus devant l''immeuble", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "details": "Selver ABC en bas de l''immeuble et coop à 3 minutes de marche.", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "2 portes à badger pour arrive à son étage et encore portes des appartements et des chambres fermables à clé.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": null}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "330"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Une bonne idée est de se faire une carte coop au magasin situé à côté du bâtiment Delta (beaucoup de réduction accessible grâce à la carte)"}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": null}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Modéré"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": null}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": null}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Modéré"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "3", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": null}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": null}, {"type": "textarea", "label": "Points forts de votre expérience", "value": null}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": null}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2025-02-23', 'Université de Tartu', 2024, 'Tartu', 'Estonie', 'alternant', true, 'Thomas', 'Bernard', 'thomas.bernard@hotmail.fr');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (9, '[{"questions": [{"type": "text", "label": "Nom", "value": "Charrié"}, {"type": "text", "label": "Prénom", "value": "Loïc"}, {"type": "email", "label": "Email", "value": "loic.charrie.12@gmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "23"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Chicoutimi"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQAC"}, {"type": "select-one", "label": "Type de programme", "value": "Cohorte"}, {"type": "date", "label": "Date de début", "value": "2024-08-28"}, {"type": "date", "label": "Date de fin", "value": "2024-12-18"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1000"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "idk"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "J''ai pris l''offre carte prestige du crédit agricole avec réduction: 17€/mois.\n\nhttps://www.credit-agricole.fr/particulier/compte/service-bancaire/offre-prestige.html\n\nPaiements Canada et USA : aucun problème."}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "Mise en veille du contrat mais j''ai eu une prime équivalente au 4 mois de salaire sur mon bulletin d''aout.\nOPCO ATLAS : remboursement sur justificatifs: 2500€\nAide Occitanie: 600€"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Oui", "details": "Entente entre France et Québec pour assurance maladie : formulaire SE401-Q-106 : Grâce à cette entente on peut bénéficier de la RAMQ ( équivalent de la CPAM au Québec) gratuitement. Demande de la RAMQ à faire depuis le site internet une fois arrivé sur le territoire  : https://www.ramq.gouv.qc.ca/fr/citoyens/assurance-maladie/inscrire."}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "J''ai pris une assurance international via le service APRIL avec les garanties suivantes (228€ pour le séjour) : \nAssistance rapatriement\nIndividuelle accident\nResponsabilité civile vie privée, stages et locative\nAssurance bagages et effets personnels\nAssistance psychologique et juridique\nIncidents de voyages et interruption de séjour\n\nJ''avais également deux autres assurances en France qui me couvrait pour un séjour à l''étranger. Il y avait des doublons avec l''assurance APRIL mais je préférais être bien assuré."}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Oui", "details": "Demande de l''AVE avant le voyage (7$) : https://www.canada.ca/fr/immigration-refugies-citoyennete/services/visiter-canada/ave.html\n\n72h avant le vol, j''avais rempli à l''avance le formulaire de douane sur une appli dédiée.\n\nInfo ici: https://www.canada.ca/fr/agence-services-frontaliers/services/arrivecan/declaration.html"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Forfait FREE ( 20€/mois) : 210go en France et 25go à l’étranger dont Canada/USA.\nAucun problème, meilleur rapport qualité/prix à l''époque.\nAttention cependant à certains numéros de services du Québec (exemple RAMQ): gratuit uniquement depuis des forfaits ou fixes Canadiens et très cher avec nos forfaits français."}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Programmation mobile"}, "Avis du cours": {"type": "textarea", "value": "Rien à dire. Prof et cours excellent."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Apprentissage des bases de la dernière version de ANDROID.\nProjet en groupe pour la fin du semestre."}}, {"Nom du cours": {"type": "text", "value": "BDD réparties"}, "Avis du cours": {"type": "textarea", "value": "Moyen. je n''ai pas spécialement appris grand chose et le cours était assez ennuyant."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Bases des BDD relationnelles + notion de répartition, consistance et disponibilité des données. \nProjet en fin de semestre."}}, {"Nom du cours": {"type": "text", "value": "Business Intelligence"}, "Avis du cours": {"type": "textarea", "value": "Prof excellent. Un ancien directeur d''entreprise qui propose ses retours d''expériences en tant qu''exemples. Très enrichissant d''un point de vue compréhension du monde des affaires."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Tableaux de bord, Data Warehouse, industrie 4.0, business, …"}}, {"Nom du cours": {"type": "text", "value": "BIG DATA & IA"}, "Avis du cours": {"type": "textarea", "value": "Des prérequis étaient recommandés mais nous ne les avions pas.\nLe cours était assez enrichissant et intéressant mais le prof était parfois compliqué à suivre."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "IA, machine learning, réseau de neurones"}}, {"Nom du cours": {"type": "text", "value": "Anglais"}, "Avis du cours": {"type": "textarea", "value": "Je n''ai rien appris ou presque avec ce cours pourtant j''avais des difficultés en anglais: (500 pts au TOEIC à Rodez)\n\nSi je peux donner un conseil aux personnes en difficulté en Anglais c''est de lire des livres, regarder des séries en Anglais (VO sous titrées) et s''entrainer sur une plateforme type global exam et ça tous les jours. J''ai profité de mon séjour d''étude pour vraiment mettre en place cette habitude.\nLa régularité paye toujours : j''ai obtenu, au final, 815 au TOEIC"}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Nous étions par groupe de niveau."}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "15"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "3", "details": "Beaucoup d''étudiants internationaux dans les cours d''informatiques. Avec 15h de cours par semaine et des cours au choix, compliqué de vraiment tisser des liens.", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Soirée d''intégration"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "details": "Ambiance très sympa dans les bars à coté de l’université.", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": null}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Rien à dire, les Québécois sont très accueillants", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Les Québécois dinent à 17h le soir, c''était assez surprenant au début."}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "4", "details": "Il y a au final peu de différence entre le Québec et la France en terme de culture.\nLe mode de vie à l''américaine est moins excessif au Québec par rapport au USA j''ai trouvé.\nLe tutoiement est omniprésent, personne ne se vouvoie donc ça peut faire bizarre au début mais on s''y fait assez vite.\nLes pourboires dans les restaurants quasi-obligatoires ( de 10 à 20%) c''était un peu pénible surtout dans les bars.\nBon en tant que Aveyronnais, le fromage , la charcuterie, l''aligot et le bon pain m''ont un peu manquées mais bon j''ai survécu.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "La poutine, la spécialité phare du Canada.\\nPour le reste rien ne vaut la France."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": null}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "375"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "0", "details": "Assez facile sur Airbnb, on a eu un coup de cœur pour un logement en campagne à 15 min en voiture de l''université. On était en coloc à 3. \nPour les fans de nature et de sport comme moi c''était vraiment super.", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "1125/mois pour le logement que l''on divisé en 3.\nJe pense que c''est dans les prix mais nous avons regardé surtout l''emplacement."}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "details": "Nous n''avons manqué de rien, le logement était vraiment très bien.", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "Parfait rien à dire", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "3", "details": "Nous avions la voiture donc pas de souci pour les transports. Sans voiture ça aurait été peut être plus compliqué à gérer.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "4", "details": "Nous avions un supermarché à 3 min en voiture donc très bien.", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Quartier majoritairement de personnes retraités donc super paisible et 0 problème de sécurité comme l''ensemble du Québec de manière générale.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": null}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1500", "details": "Sur mon voyage complet en comptant le vol, les coûts liés à la voiture, un semaine à New York , une semaine à Toronto, l''ensemble des coûts de la vie quotidienne (Courses, restaurants, ...) je suis au alentour de 7000€ de dépense totale.\nJe ne me suis pas du tout privé mais j''ai fait gaffe ; si on va plusieurs fois par semaines dans les bars et restau, je pense qu''on monte vite à 10k €"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Elevé"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Si vous souhaitez manger à la française ça coute effectivement plus cher (la viande notamment, .. ). Oubliez le fromage si vous ne voulez pas plomber le budget.\nChoisir les légumes/fruits de saisons et les articles en promo peut être un bon conseil je pense."}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "Nous avons fait pas mal d''activité de plein air ( rando, ... )\nAttention les accès à certaines rando dans les parcs nationaux sont payant"}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Très élevé"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "Passez par un forfait Français, les forfaits canadien sont inapprochables."}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Nous n''avons pas eu besoin des transports mais une offre était faite avec l''université en début de semestre."}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Elevé"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Peut être plus d''info sur les démarches à réaliser."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Je retiens de ce séjour que des bonnes choses; ça a été pour moi une merveilleuse découverte, une aventure enrichissante et je conseille vraiment à tout le monde de vivre une telle expérience."}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "La gentillesse des gens, le mode de vie, les grands espaces canadiens ..."}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "Je n''ai éprouvé aucune difficulté spécifique"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-27', 'UQAC', 2024, 'Chicoutimi', 'Canada', 'alternant', true, 'Julien', 'Martin', 'julien.martin.12@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (13, '[{"questions": [{"type": "text", "label": "Nom", "value": "JUERY"}, {"type": "text", "label": "Prénom", "value": "Géraldine"}, {"type": "email", "label": "Email", "value": "geraldinejuery.pro@gmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "23"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Gatineau"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQO"}, {"type": "select-one", "label": "Type de programme", "value": "Echange bilatéral"}, {"type": "date", "label": "Date de début", "value": "2023-08-28"}, {"type": "date", "label": "Date de fin", "value": "2023-12-18"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1241.54"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "idk"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Oui", "details": "AVE (visa de visiteur)"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Non"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Allianz Travel, assurance voyage"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Orange Pass USA/Canada à renouveler chaque mois du voyage"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "CYB1073-Cybersécurité comportementale"}, "Avis du cours": {"type": "textarea", "value": "Thème très intéressant mais cours monotone (l''enseignant lit son pdf), en plus, en visio jusqu''à 22h."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours en visio le soir. Programme : étude des risques (humains et techniques), méthodes et techniques de cyber-attaques (comportementales). 2 projets en groupe (rapport + présentation) sur des sujets imposés + 2 évaluations (mi-session et fin de session) sur Moodle."}}, {"Nom du cours": {"type": "text", "value": "INF5183-Fondements de l''intelligence artificielle"}, "Avis du cours": {"type": "textarea", "value": "Cours intéressant et simple, il est facile d''obtenir de très bons résultats."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours en visio le soir. Programme : découverte de l''IA. Plusieurs petits DM à rendre (très simple), + 2 évaluations (mi-session et fin de session) sur Moodle + 1 gros projet divisé en plusieurs présentations sur le thème de notre choix."}}, {"Nom du cours": {"type": "text", "value": "INF6083-Sujets spéciaux (Traitement des informations dans les réseaux)"}, "Avis du cours": {"type": "textarea", "value": "Au début, très déstabilisant et compliqué. Un seul support : un cours de 57 pages de texte (sans schémas !) . Il faut beaucoup de travail personnel et s''entraider pour les devoirs si l''on veut réussir et comprendre. A la fin du trimestre, nous n''étions plus que 5 élèves dans le cours, beaucoup ont abandonnés."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours en présentiel. Programme : ne pas se fier au titre, le cours porte uniquement sur les algorithmes. 2 devoirs +  2 évaluations (mi-session et fin de session) papier."}}, {"Nom du cours": {"type": "text", "value": "INF6343-Intelligence artificielle distribuée"}, "Avis du cours": {"type": "textarea", "value": "On voit beaucoup d''aspects de l''IA et notamment sur la théorie des jeux. Très axé sur le domaine du jeu. L’enseignant nous prépare très bien pour l''examen avec des annales des années précédentes."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours en présentiel. Programme : Agents, multi-agents, choix collectif, théorie des jeux, machine learning... 2 devoirs + une présentation + un examen final sur papier + un projet de groupe."}}, {"Nom du cours": {"type": "text", "value": "MGP7111A-Project Management and its Environment"}, "Avis du cours": {"type": "textarea", "value": "Le cours est assez simple, malgré qu''il soit donné en anglais car les notions ont déjà été vues en France pour la plupart. L''enseignante prend le temps d''expliquer en français si besoin."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours en semi-présentiel. En anglais. Programme : Tous les aspects de la gestion de projet. 1 devoir à faire seul + 2 devoirs en groupe + 2 évaluations (mi-session et fin de session) sur Moodle."}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "15"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "3", "details": "Il était plus facile de s''intégrer avec les étudiants internationaux que les locaux.", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": null}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Les habitants viennent facilement discuter et s''intéressent à ce que l''on fait."}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Quand on va faire ses courses (à Métro notamment), il y a quelqu''un à la caisse pour nous ranger les courses dans le sac !"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Poutine, queue de castor, plats cuisinés avec de l''érable.."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Oui", "details": "Il y a beaucoup moins de violence qu''en France et plus de respect, dans le quartier où nous étions mais aussi les villes que nous avons visitées."}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Bienvenue = De rien ! (Nous nous en sommes rendu compte au bout de 3 mois !)\nAttention aux dépanneurs (petits commerces de proximité). On n''y trouve pas toujours de quoi manger (un vrai repas !) et c''est souvent très cher."}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Les vidéos YouTube d''un couple français qui sont allés vivre à Gatineau : Stenn & Flora. En plus, ils répondent aux MP Instagram ! (Je leur avais demandé conseil pour une visite que nous voulions faire)."}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "2000", "details": "L''appartement était très cher mais nous étions 2 pour payer (mon compagnon est venu avec moi)."}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "4", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": null}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "4", "details": "A l''étage d''une épicerie. Situé à 3min à pied de l''université. Très bien, seul défaut : pas très bien isolé.", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "2 chambres, grande salle de bain, cuisine un peu petite, salon, TV connectée, WiFi, lave-linge, sèche-linge.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "details": "Arret de bus en bas de l''appartement. Sur la ligne qui rejoint le centre commercial et Ottawa.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "details": "Le propriétaire possède l''épicerie en dessous (cher, mais on trouve de tout). Facile et rapide d''aller au centre commercial en bus.", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "L''appartement est sécurisé avec un code. Le quartier est très calme avec un parc de l''autre coté de la route et à quelques kms du grand parc de la Gatineau. Idéal pour les étudiants qui n''aiment pas la ville !", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Bien lire les commentaires sur Airbnb."}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "4000", "details": "En comptant l''appartement, les courses et tous les voyages (Montréal, Québec, Toronto, les Chutes du Niagara, Parc Oméga). Coût pour 2 personnes."}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Elevé"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Maxi est moins cher que Métro mais on n''y trouve pas de produits français (Roquefort par exemple !). Il y a plus de choix à Métro, mais c''est beaucoup plus cher."}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Elevé"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "Parc de la Gatineau, marchés de Noel."}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Elevé"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "Même si je n''ai souscrit à aucun forfait, j''avais fait des comparaisons avec mon forfait français et le forfait français était moins cher."}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Elevé"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "3.80 $ le trajet de bus  avec la carte de bus STO, 110 $ par mais pour l''abonnement.\nPour louer une voiture : TURO est une super application de particulier à particulier donc il est possible d''avoir des belles voitures pour pas cher mais il faut avoir 23 ans minimum (tous les particuliers ne le vérifie pas !). Sinon, il y a RENTACAR, pas de limite d''age mais plus cher car il faut prendre une assurance jeune en plus.\nPour le train, la compagnie c''est VIARAIL. Possibilité d''avoir des tarifs plutôt bas (tarif Evasion) mais il faut s''y prendre à l''avance et c''est souvent des horaires matinales qui sont disponibles (5h ou 6h du matin). Les voyages en train sont très long car les trains de marchandises sont prioritaires là-bas."}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Elevé"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Avoir le détail des cours et pas uniquement les titres avant de choisir pour éviter les mauvaises surprises."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": null}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "- Le fait de pouvoir construire son planning de cours. En s''organisant bien, on peut avoir des week-end de 4 jours chaque semaine, idéal pour partir visiter (sans oublier de travailler bien sur !).\n- La visite aux Chutes du Niagara !"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": null}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2025-02-13', 'UQO', 2023, 'Gatineau', 'Canada', 'alternant', true, 'Sophie', 'Leroy', 'sophie.leroy.pro@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (11, '[{"questions": [{"type": "text", "label": "Nom", "value": "ROSIER"}, {"type": "text", "label": "Prénom", "value": "Wendy"}, {"type": "email", "label": "Email", "value": "rosier.wendy98@gmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "27"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Espagne"}, {"type": "text", "label": "Ville", "value": "Huelva"}, {"type": "text", "label": "Établissement d''accueil", "value": "UHU Huelva"}, {"type": "select-one", "label": "Type de programme", "value": "Erasmus"}, {"type": "date", "label": "Date de début", "value": "2022-09-12"}, {"type": "date", "label": "Date de fin", "value": "2023-01-31"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Train"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "140"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Espagnol"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Non"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Non"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "Aide Erasmus"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "10 € --> 50Go Vodafone"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Administration Serveur"}, "Avis du cours": {"type": "textarea", "value": "Très complet"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Base de l''administration Linux, virtualisation, etc..."}}, {"Nom du cours": {"type": "text", "value": "Réseau Avancé"}, "Avis du cours": {"type": "textarea", "value": "La passage de la certification est un avantage non négligeable"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Etude des différentes topologies, protocole de routage, VPN, TP Cisco, passage de la certification Cisco"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "5", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "12"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "5", "details": "Les locaux sont chaleureux, ne pas hésiter à s’inscrire à des groupes Watsapp erasmus, pour ne pas manquer les évenements (fêtes, soirées, voyages, etc...)", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Présentation de l''université par le directeur"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Optez pour une colocation, cela vous permettra de ne pas vous isoler et de connaître du monde. Le niveau des cours peut-être soutenu, mais cela derniers ne vous empêchera pas de profiter de votre Erasmus. Voyagez, sortez, mélangez-vous aux autres étudiants Erasmus, vous ne le regretterez pas !"}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Très chaleureux !", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Enrichissant"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Non"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Ne soyez pas timide, les espagnols sont en général très amicaux. Les autres étudiants Erasmus sont aussi très ouverts."}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Les groupes Watsapp"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "270"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Très bon rapport qualité/prix. Nous étions 4 dans collocation"}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Site de petites annonces"}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "500", "details": "Huelva n''est pas cher en terme de coût de la vie. Pour les sorties aussi, les verres ne sont pas chers, et si vous joignez des groupes watsapp, ces derniers peuvent vous faire des offres pour l''entré de certaines soirées, voyages, etc..."}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": null}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Bas"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": null}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Bas"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": null}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": null}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Bas"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": null}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": null}, {"type": "textarea", "label": "Points forts de votre expérience", "value": null}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": null}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2025-01-28', 'UHU Huelva', 2022, 'Huelva', 'Espagne', 'alternant', true, 'Camille', 'Moreau', 'moreau.camille98@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (7, '[{"questions": [{"type": "text", "label": "Nom", "value": "Lefebvre"}, {"type": "text", "label": "Prénom", "value": "Theo"}, {"type": "email", "label": "Email", "value": null}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Non"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "26"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Chicoutimi"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQAC"}, {"type": "select-one", "label": "Type de programme", "value": "Cohorte"}, {"type": "date", "label": "Date de début", "value": "2022-08-29"}, {"type": "date", "label": "Date de fin", "value": "2022-12-21"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "900"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "idk"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "J’ai souscrit à une carte bancaire orange pour éviter de payer les taxes sur chaque frais imposer par ma carte credit mutuel."}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "OPCO, 1200e, remplir la note de frais avec les justificatifs"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Oui", "details": "Demande de la RAMQ, puis fournir la preuve à l’établissement scolaire"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Oui", "details": "A la douane"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Free est le seul opérateur qui fournit beaucoup de Go internet à l’étranger sans abuser sur le prix. 35 Go internet et 5 Go pour appel vers l’étranger. Les forfait Canadien sont extrêmement cher."}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Base de données repartie"}, "Avis du cours": {"type": "textarea", "value": "Cours intéressant"}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Base de données réparties, sécuriser les données, projets sous Oracle visant à construire une base de données repartie"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "3"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Journée d’intégration avec différents stands au sein de l’UQAC (association, nourriture, etc), puis une soirée d’intégration"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "details": "Pas mal de choses mise en place autour du sports, des jeux vidéos, mais moins pour les soirées étudiantes. Pas de BDE", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Prendre une collocation est un très bon moyen de s’intégrer avec d’autres étudiants avant de commencer ça mobilité"}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "4", "details": "Les locaux sont des personnes très accueillantes et apprécient les Français (cela dépend un peu plus de la personne chez les jeunes)", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Rencontre avec les baleines à Tadoussac, baseball en cage à Montreal, match de Hockey à l’arène Centre Bell, rencontre avec les ours et ratons laveurs lors de la visite du parc de la Mauricie, dégustation de poutine."}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Non"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "details": "Adaptation très simple, malgré le froid de l’automne et le coucher de soleil très tôt. Quelques difficultés au départ à comprendre l’accent et les expressions Québécoise mais cela disparaît avec le temps.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Poutine, Bison, Wapiti, bière IPA, sirop d’érable."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": null}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "475"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "3", "details": "Difficile de trouver une collocation pour 6 proche de l’université. Nous avons chercher sur Facebook où il y avait le plus d’offres.", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Très correcte comparer aux autres logements"}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "details": "Une grosse maison sur 2 étages (dont qui  est aménagé au sous-sol) avec tout ce dont nous avions besoin. L’aspirateur est un tuyau qui s’accroche au mur et qui est très long pour pouvoir faire les 2 étage, très peu pratique.", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "La maison était entièrement équiper (exception pour les plats pour le four) et très confortable", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "details": "À 5-10min de tout à pied", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "details": "À 5-10min de tout à pied", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Quartier très calme et paisible, les maisons ne dispose pas de murs/clôtures.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Chercher sur les groupes de logements Facebook ou Leboncoin"}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "700", "details": "Loyer, courses alimentaires et alcool pour 2 soirée par semaine"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Elevé"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Environ 250 à 350 euro pour 6 pour 10 jours en ce restreignant"}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "Match de Hockey et football américain universitaire. Visite de Saguenay et du fjord."}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Bas"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "C’est l’opérateur free que nous avions tous utilisé car les forfaits Canadien sont très cher (environ 70e). 19,99 chez free pour 35 go internet."}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Pas utiliser durant notre mobilité"}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Elevé"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Améliorer les communications concernant la mise en veille des contrats."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Cela a eu très peu d’impact pour moi, certains cours n’avait aucun intérêt pour mes perspectives professionnelles"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "La beauté des paysages, le climat et les locaux."}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "Avoir 21 ans et carte de crédits et non débit pour louer une voiture. Faire 10 min de route à pied avec le cadis pour ramener les courses."}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-26', 'UQAC', 2022, 'Chicoutimi', 'Canada', 'alternant', false, null, null, null);
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (8, '[{"questions": [{"type": "text", "label": "Nom", "value": "Dewailly"}, {"type": "text", "label": "Prénom", "value": "Florian"}, {"type": "email", "label": "Email", "value": "dewaillymontet.pro@gmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "24"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Roumanie"}, {"type": "text", "label": "Ville", "value": "Bucarest"}, {"type": "text", "label": "Établissement d''accueil", "value": "UPB"}, {"type": "select-one", "label": "Type de programme", "value": "Erasmus"}, {"type": "date", "label": "Date de début", "value": "2022-10-03"}, {"type": "date", "label": "Date de fin", "value": "2023-02-20"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "300"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Anglais"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Non"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Non"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "Aide Erasmus"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Assurance lié à ma carte bancaire N26 (AXA)"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Vodafone à des prix imbattables, je vous conseille de vous prendre une deuxième sim là bas auprès de Vodafone, vous aurez de la 4G très peu chère."}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Pentest (Nom non exacte)"}, "Avis du cours": {"type": "textarea", "value": "Bon cours"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Apprentissage du pentest, les failles les plus connus (SQLi, XSS, etc)"}}, {"Nom du cours": {"type": "text", "value": "FPGA (Nom non exacte)"}, "Avis du cours": {"type": "textarea", "value": "Bien mais le prof est le moins bien de ce double diplôme."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Codage cryptographique FPGA"}}, {"Nom du cours": {"type": "text", "value": "Développement Accès CyberSec (nom non exacte)"}, "Avis du cours": {"type": "textarea", "value": "."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Développement avec des Test, Apprentissage des failles les plus courantes lors du développement."}}, {"Nom du cours": {"type": "text", "value": "Éthique"}, "Avis du cours": {"type": "textarea", "value": "Agréable et pas de prise de tête, il s''agit d''un cours pour aider à faire les bon choix avec les compétences que vous allez acquérir"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Notions d''éthique, ce qui est bon et ne l''est pas, ce qui est autorisé par la loi, etc."}}, {"Nom du cours": {"type": "text", "value": "Management de sécurité Info"}, "Avis du cours": {"type": "textarea", "value": "Semble intéressant"}, "Notez ce cours": {"type": "rating", "value": "0", "option": "note"}, "Description du cours": {"type": "textarea", "value": "0 en note car le cours n''as pas été dispensé car la prof avait un problème, il fut remplacé par le cours de pentest. Néanmoins on a eu accès aux documents et le cours est intéressant. Ça parle de gouvernance, gestion des risques, etc."}}, {"Nom du cours": {"type": "text", "value": "Management d''incident cyber"}, "Avis du cours": {"type": "textarea", "value": "Bien et le prof est intéressant."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Différent de \"Management de sécurité Info\" car dans ce dernier on va parler des failles, de simulation d''attaque et de comment réagir."}}, {"Nom du cours": {"type": "text", "value": "Projet de recherche"}, "Avis du cours": {"type": "textarea", "value": "J''ai dépassé la note de 5 car c''est génial, vous allez énormément augmenter vos compétences et être entouré de prof compétent."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours en autodidacte suivi par un professeur chercheur. L''objectif est de faire une innovation dans le monde de la cybersecurité. Foncez !"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "5", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "12"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "5", "details": "À peine arrivé vous êtes ajouté par les responsables Erasmus dans un groupe étudiant avec tous les Erasmus de la fac. Pleins de soirée autonome ou organisé par le comité Erasmus.", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Speed meetings, soirée, découverte de la ville, et d''autres que j''ai zappé"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Oui", "details": "."}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "5", "details": "Vous avez énormément de temps pour faire ce qui vous chante, profitez en, le dernier semestre de 3IL vous laisseras moins de temps libre.", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Vive a fonds et dépensez le plus possible. N''oubliez pas que vous avez accès à la majorité des évènements Erasmus du monde donc VOYAGEZ. (Ibiza trip, Sea Battle, Dracula Halloween, etc). De plus vous avez aussi accès via la carte Erasmus aux soirées des autres groupes Erasmus, du pays où à l''international."}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Génial, on vous offre de l''alcool local (beaucoup de palinka) et vous racontes l''histoire du pays où de la région.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Non"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "details": "Pas tant de différence, pays européens et chrétiens (orthodoxe) avec une langue latine.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Je ne saurais les écrire mais vous allez en découvrir pas mal."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Oui", "details": "Très religieux, les taxis font la croix en passant à côté d''une église."}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Faites pas les cons, soyez respectueux et tout se passera bien."}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Vidéo youtube, bouquin"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "600"}, {"type": "select-one", "label": "Type de logement", "value": "Logement privé"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "4", "details": "Difficile, ils ont moins cette culture de la location que nous vu que c''est un ancien pays communiste.", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Génial, à 100 mètres de la fac, d''un Cora et du métro. 50 mètres carré avec tout ce qu''il faut."}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "details": "Dans le centre c''est généralement plus vieux et vétuste mais c''est là où il y a le plus d''Erasmus. Beaucoup de colocation.", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "Lave vaisselle, lave linge, télé, wifi, etc. Juste prévoyez d''acheter sur place des couverts et plats.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "details": "Tout est faisable en transport, de plus bolt (concurrent à Uber) ne coûte rien par rapport à ici)", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "details": "Y en a partout et ouvert jours comme nuit (généralement ouvert jusqu''à 4h mais certains ferme avant, voir ne ferme pas)", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Très très sécurisé, les voleurs étaient des Erasmus. Faites attention à la rigueur aux gens du voyage, sinon c''était extrêmement sur, rien a voir avec la France.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Via agence immobilière, ou demander aux Erasmus sur place s''ils ont des tuyaux. Il existe aussi des groupes Facebook pour ça."}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1000", "details": "Loyer + nourriture + transport ça vous ferra sûrement quelques chose comme ça, en colocation ça diminuera beaucoup. J''ai pris un chiffre large."}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Sincèrement c''est pas si différent de la France la dessus donc attention."}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Bas"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "Visite, prenez un train ou une voiture et go voyager."}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Très bas"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "Très bas par rapport à ici, je ne veux pas dire de bêtises mais pour 5€ de mémoire j''avais un forfait au mois."}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Bas mais je n''ai plus le montant en tête, quelques centimes de mémoire et payable directement avec votre téléphone en sans contact."}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Bas"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Foncez c''est génial et peu cher."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Ça m''a beaucoup aidé à progresser dans la vie, vous sortirez sûrement de cette expérience grandi."}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Prix peu cher donc possibilité de faire littéralement tout ce que vous voulez, de plus comme c''est un pays sûre vous pouvez sortir à pas d''heure sans être emmerdé."}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "La langue au début n''étant pas bilingue."}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-26', 'UPB', 2022, 'Bucarest', 'Roumanie', 'alternant', true, 'Antoine', 'Petit', 'petit.antoine.pro@gmail.com');
