, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Oui", "details": "Orthodoxe"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Etre méga curieux et ne pas juger sur ses valeurs mais essayer de comprendre leurs histoires"}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Les bulgares, ils faut parler aux gens"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "530", "details": "Cher mais j''étais au coeur de la ville"}, {"type": "select-one", "label": "Type de logement", "value": "Logement privé"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "3", "details": "AirBnb, mais en vrai c''est cher", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": null}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "4", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "4", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "J''ai l''impression que les rues sont sûres en Bulgarie comparé à en France", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": null}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1200"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "La viande et le laitage c''est cher"}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "ça dépend mais en vrai c''est toujours moitié moins qu''en France"}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Modéré"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "Je sais pas trop"}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Alors la par contre ! Vous faites pas avoir !\nIl faut aller au guichet qui est proche de l''université et il faut montrer sa carte d''identité.\n\nQUE CE GUICHET, sinon les autres vont vous arnaquer (25€ le mois au lieu de 12.5]"}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Bas"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "J''ai adoré, faites des randonnées , puis visiter les pays autour.\nMEME SI CEST DANS L''UE FAITE VOTRE PASSPORT. J''ai pas pu visiter la Serbie...."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Une envie de voyager , une vision du monde qui a changé"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Prix bas, débrouillar, sortir de sa zone de confort"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "La solitude par moment"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2025-02-22', 'UTS Sofia', 2024, 'Sofia', 'Bulgarie', 'alternant', true, 'Hugo', 'Lambert', 'hugolam64@gmail.com');
