INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (12, '[{"questions": [{"type": "text", "label": "Nom", "value": "Mzouri"}, {"type": "text", "label": "Prénom", "value": "Wassim"}, {"type": "email", "label": "Email", "value": "mzouri.wassim@gmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "24"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Slovénie"}, {"type": "text", "label": "Ville", "value": "Maribor"}, {"type": "text", "label": "Établissement d''accueil", "value": "Université de Maribor"}, {"type": "select-one", "label": "Type de programme", "value": "Erasmus"}, {"type": "date", "label": "Date de début", "value": "2023-10-30"}, {"type": "date", "label": "Date de fin", "value": "2024-02-28"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "270"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Anglais"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Non"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Faire attention aux assurances et j’ai ouvert un compte bancaire d’une banque en ligne permettant de réduire les frais à l’étranger"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "Aide Erasmus"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Oui", "details": "Documents pour obtenir un permis de résidence en Slovénie"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Mon forfait était à l’international mais au bout d’un certain seuil : \nLorsque vous passez un certain temps à l’étranger et que au bout de deux mois consécutif vous avez résider plus longtemps à l’étranger des frais vous seront facturé. J’ai pris une carte SIM facilement trouvable dans des magasins (SPAR) et je l’ai rechargé le temps qu’il me rester la bas. ( environ 1 mois avec cette carte SIM )"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Développement web"}, "Avis du cours": {"type": "textarea", "value": "Très bien"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Nouvelle techno etudié et professeur très bien le tout était bien renseigné sur moodle"}}, {"Nom du cours": {"type": "text", "value": "Cyber sécurité"}, "Avis du cours": {"type": "textarea", "value": "Bien mais avec 2 professeurs différents et chacun son évaluation"}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Pour un débutant c’est un petit peu avancé mais avec du travail vous pouvez réussir"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "25"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "3", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Oui", "details": "La communication et les informations sont à allez chercher par vous même. Il m’ai arriver de rater des cours car je n’étais pas au courant : un professeur s’est rendu compte trop tard que j’étais inscrit à son cours et ne m’avais pas dit que ce dernier commence. Je n’ai pas pu faire l’exam final…"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Non"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "3", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Welcom weeks ( à l’arriver séjour pour visiter la Slovénie)\nGroupe télégram avec plein d’activités proposées dont soirée étudiante Erasmus toutes filières confondue."}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Allez dans le groupe telegram et n’hésitez pas envoyer des messages si vous voulez faire des sortie ou même manger dehors si vous n’aimais pas la solitude ahah."}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Pays très très bienveillant. Les gens sont chaleureux et très gentils.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Non"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "4", "details": "En Slovénie les gens se lève tôt et les commerces ferment tôt aussi. Tous se passe dans le début de journée et l’après midi chacun réalise leurs hobbie, affaires etc…", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Je n’ai plus les noms mais la bas le régime alimentaire et base avec du poulet porc patate et plusiseurs plat locaux très bon"}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": null}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "400"}, {"type": "select-one", "label": "Type de logement", "value": "Logement privé"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "3", "details": "Beaucoup de demande il faut s’y prendre à l’avance", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Comme en France"}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "4", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "4", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "au pire des cas, vous pouvez trouver des hôtels qui font des locations de longue durée. Si vous voulez un logement personnel, il y a des agences immobilières qui vous permettront de trouver des appartements. Si vous voulez des collocation, cela se passe sur les sites Internet et n’hésitez pas à appeler Les propriétaires pour savoir si il reste de la place."}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "600"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Sans aliments comme le fromage ou la viande sont un peu plus cher, mais il reste des bonnes qualités"}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "Cela dépend des activités, mais en général ce n’est pas très cher"}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Bas"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "si vous voulez acheter une SIM avec des gigas à l’étranger, cela n’est pas cher de l’ordre de 10 € pour 100 giga"}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": null}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Bas"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "4", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": null}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Ce séjour m’a permis de améliorer mon anglais et de prendre en responsabilité car vous êtes seuls à l’étranger. Et dans ce cas là il faut se débrouiller seul. Niveau académique cela était très intéressant mais un peu compliqué et avec une communication parfois inexistante je n’ai pas eu l’opportunité d’avoir beaucoup de Français avec moi, mais certainement que si il y en avait Cela aurait pu être plus simple et j’aurais eu plus d’informations"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "le Voyage en lui-même, le cadre de la Slovénie qui est très apaisant et la vie. Le Maribor est petite mais avec tout ce qu’il faut tout peut se faire à pied. Les gens là-bas sont très gentils et j’ai pu voyager autour de ce pays qui est entouré de Magnifique pays ( Croatie, Hongrie, Autriche…)"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "m’adapter au système d’éducation de la Slovénie. S’ouvrir aux gens et ne pas hésiter à parler anglais. Devoir faire de l’administratif, même en anglais"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2025-01-30', 'Université de Maribor', 2023, 'Maribor', 'Slovénie', 'alternant', true, 'Léa', 'Simon', 'simon.lea@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (18, '[{"questions": [{"type": "text", "label": "Nom", "value": "Ferraye"}, {"type": "text", "label": "Prénom", "value": "Nicolas"}, {"type": "email", "label": "Email", "value": "ferraye.nicolas@sfr.fr"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "21"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Lettonie"}, {"type": "text", "label": "Ville", "value": "Riga"}, {"type": "text", "label": "Établissement d''accueil", "value": "Riga Technical University"}, {"type": "select-one", "label": "Type de programme", "value": "Erasmus"}, {"type": "date", "label": "Date de début", "value": "2024-08-26"}, {"type": "date", "label": "Date de fin", "value": "2025-01-26"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Voiture"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Anglais"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Non"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Carte permettant le paiement de devises étrangères. En effet, j''ai traversé la Tchéquie et la Pologne, qui sont hors zone euro."}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "OPCO\nErasmus\nOccitanie"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Assurance rapatriement obligatoire cf. mail 3iL"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Non"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Knowledge Management Systems"}, "Avis du cours": {"type": "textarea", "value": "Travaux de groupe, peu de travail individuel. Contrôle continu + présentation finale de classe. Enseignement hybride possible"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Transmission de la connaissance en entreprise"}}, {"Nom du cours": {"type": "text", "value": "Requirement Engineering"}, "Avis du cours": {"type": "textarea", "value": "Travaux de groupes et individuels"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Informatique décisionnelle, modélisation, business"}}, {"Nom du cours": {"type": "text", "value": "Entreprise Information Technology Architecture, Application and Integration"}, "Avis du cours": {"type": "textarea", "value": "Trop d''ERP par rapport aux microservices et architectures logicielles. En visio."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Utilisation des ERP (MS Dynamics, SAP), comptes-rendu d''études scientifiques, microservices"}}, {"Nom du cours": {"type": "text", "value": "Evolution of Object-Oriented Software"}, "Avis du cours": {"type": "textarea", "value": "Professeur compétent, mais valide individuellement les TP des étudiants (prend beaucoup de temps inutilement). Peu d''intérêt d''apprendre l''Ada. Uniquement en présentiel"}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Ada, Java, Python"}}, {"Nom du cours": {"type": "text", "value": "Software Evolution Technologies"}, "Avis du cours": {"type": "textarea", "value": "Prof condescendant. Beaucoup de contrôle continu. Certains cours uniquement en présentiel, puis bascule en distanciel."}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "UML, méthodologies (Delfi, Agile, TDD), présentation d''études scientifiques"}}, {"Nom du cours": {"type": "text", "value": "System Analysis and Knowledge Acquisition"}, "Avis du cours": {"type": "textarea", "value": "Bons professeurs et intervenants"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Modélisations (UML, 4EM), informatique décisionnelle\""}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "5", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "30"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "5", "details": "Beaucoup d''étudiants français, grosse proportion d''étudiants étrangers, tous très anglophones", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Présentations, stands, soirée"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "5", "details": "Manque de soirées dans les activités ESN (le BDE local pour les Erasmus)", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Avoir un bon niveau en anglais (B2 minimum obligatoire pour l''université). Apprendre le letton et le russe est un gros plus.\n\nLes lettons sont très introvertis : il faut savoir briser la glace. Beaucoup de russophones (pays de l''ex-URSS) : l''apprentissage du russe facilite les interactions."}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "4", "details": "Les locaux sont de natures stricts et assez rudes. Racisme présent chez certains individus. Un comportement irréprochable vous sera demandé. Pour ma part, je n''ai pas eu de problème.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Commémorations de Novembre, défilé militaire pour le jour d''indépendance de la Lettonie"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Folklore très présent"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "details": "L''apprentissage du russe avant ma mobilité m''a beaucoup aidé avec les habitants russophones et non-anglophones. Parler quelques mots / phrases de la langue de votre interlocuteur (letton et/ou russe) est grandement apprécié", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "Cuisine d''Europe de l''Est : fonctionnelle. Des patates, du pain de seigle, du poulet, du porc. Beaucoup de viandes blanches mais peu de boeuf. Beaucoup de soupes aussi (la solianka par exemple). La Lettonie est à éviter si vous avez des préférences alimentaires religieuses"}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Participez aux activités de toute sorte, faites l''effort de parler quelques mots / phrases en letton et en russe. Parlez aux locaux, ne restez pas uniquement avec les étudiants. Ne parlez pas de langue étrangère de manière trop bruyante, soyez respectueux."}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Duolinguo (apprentissage du russe), Musée de la Guerre, Musée de l''Occupation, Musée Ethnographique de Riga, Musée du KGB, marchés locaux, boutiques locales, visite de la banlieue."}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "650", "details": "Le loyer peut être négocié pour les location Airbnb en long terme. Faites attention aux charges. Sur Airbnb, tout est inclu. Sinon, il faudra rajouter +150€, pour le chauffage, électricité, gaz, eau, internet etc."}, {"type": "select-one", "label": "Type de logement", "value": "Logement privé"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "5", "details": "Obligation de réservation du logement avant l''inscription : faites la réservation en avance", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": null}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": null}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1600", "details": "J''ai vécu comme un apparatchik de l''époque brejnévienne :\n- Viande tous les jours\n- Voiture (carburant + assurance)\n- Club de karaté\n- Souvenirs\n- Sorties\n\nMon cas n''est pas un exemple"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Bas"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Viande de boeuf à 15€/kg (boucherie vendant du boeuf difficile à trouver)\nGPL à 0,8€ / L, carburant pas cher"}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": "Musées, piscine universitaire, piscine de Rimi, sauna, club de karaté, club de karaté"}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Bas"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": null}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Abonnement aux transports de Riga possible avec le certificat de scolarité"}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Bas"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Apprendre le letton et/ou le russe"}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Amélioration de mon niveau en anglais, apprentissage du russe, découverte d''une autre culturelle, autonomie en pays étranger"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Ville très agréable, propre, belle architecture. Locaux accueillants, culture magnifique malgré une histoire difficile"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "Infrastructure routière compliquées sur certains axes, savoir briser la glace sur son pare-brise comme auprès des locaux (blague eco+ mdr), beaucoup de russophones non-anglophones"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2025-04-01', 'Riga Technical University', 2024, 'Riga', 'Lettonie', 'alternant', true, 'Maxime', 'Girard', 'girard.maxime@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (3, '[{"questions": [{"type": "text", "label": "Nom", "value": "Courchia"}, {"type": "text", "label": "Prénom", "value": "Sam"}, {"type": "email", "label": "Email", "value": "sam.courchia0@gmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "24"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Chicoutimi"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQAC"}, {"type": "select-one", "label": "Type de programme", "value": "Cohorte"}, {"type": "date", "label": "Date de début", "value": "2023-08-21"}, {"type": "date", "label": "Date de fin", "value": "2023-12-21"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1000"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "idk"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Oui", "details": "Pas exactement un visa mais une AVE (Autorisation de voyage électronique) d''environ 7 CAD"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Assurance mobili''jeune (Crédit mutuel), environ 100€ pour la durée du séjour, inclut une assurance rapatriement."}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Oui", "details": "Aide de la région Occitanie (Mouv Occitanie), environ 1200€ d''aide versés en deux parties : Premier versement de 60% dès la validation du dossier et deuxième versement de 40% après la fin de la mobilité sur présentation d''attestation de \"participation\" à la mobilité. Les étudiants sans mise en veille de contrat avaient reçu un refus de la part de la région dans un premier temps mais nous avons finalement reçu l''aide donc ne pas hésiter à faire la démarche dans tous les cas ! Surtout ne pas écouter Alice Fleury qui soutient le contraire."}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Oui", "details": "Au Québec, il faut souscrire à la RAMQ (un formulaire est à remplir par la CPAM, l''école et l''étudiant) sans quoi l''université d''accueil vous réclamera plus de 300 CAD correspondants à la prise en charge de l''assurance santé de leur part. Dès l''arrivée sur place, il faut faire les démarches car la réception de la carte d''assurance peut être très tardive et aucune attestation n''est remise permettant de prouver que la démarche est en cours. Ayant des problèmes de santé, je me suis retrouvé bien embêté car j''ai du me rendre à l''hôpital et tout payer de ma poche (environ 1200 CAD pour une simple consultation)."}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Inclue dans l''assurance bancaire"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Oui"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Free 20€ par mois, 30Go aux USA + Canada"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "English skills IV"}, "Avis du cours": {"type": "textarea", "value": "Cours très intéressant, enseignant dynamique et très agréable"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Anglais avancé (plusieurs groupes sont formés au début de la période en fonction du niveau). Passif, present perfect, figures de style, rédaction, invention. En résumé ça ressemblait aux cours de français que l''on fait au lycée, mais en anglais"}}, {"Nom du cours": {"type": "text", "value": "Bases de données réparties"}, "Avis du cours": {"type": "textarea", "value": "Enseignante peu intéressante bien que plutôt agréable, projets assez intéressants cependant. Avis très personnel car je ne suis pas très intéressé par ce sujet de base et nous n''avons pas pu choisir nos cours."}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Bases de données relationnelles, optimisation de bdd, le reste j''ai lâché..."}}, {"Nom du cours": {"type": "text", "value": "Intelligence d''affaires, principe et méthodes"}, "Avis du cours": {"type": "textarea", "value": "Enseignant qui connaît très bien son sujet, projets en groupe à rendre toutes les semaines ce qui permet de bien comprendre toutes les notions abordées"}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Beaucoup de notions sur le BI, compliqué à décrire"}}, {"Nom du cours": {"type": "text", "value": "Programmation de plateformes mobiles"}, "Avis du cours": {"type": "textarea", "value": "Enseignant qui connaît encore une fois très bien son sujet, il va droit au but quand il explique les choses et est très disponible si besoin d''aide sur le projet."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Réalisation d''une application mobile de A à Z. Différentes notions abordées à chaque cours en parallèle du projet de réalisation de l''appli ce qui permet de faire les choses dans l''ordre"}}, {"Nom du cours": {"type": "text", "value": "Apprentissage automatique pour données massives"}, "Avis du cours": {"type": "textarea", "value": "Prof très sympathique mais on part avec un handicap, le cours nécessite des connaissances de base en machine learning, il est conseillé de se désinscrire si on n''a pas ces connaissances. La thématique n''étant pas abordée à 3iL, il est très compliqué de suivre ce cours."}, "Notez ce cours": {"type": "rating", "value": "1", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Machine learning, scikit learn, perceptron (des mots que j''ai vaguement entendus lorsque j''arrivais à me concentrer sur le cours). Deux projets notés faisables avec chatGPT"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "15"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "2", "details": "Tous les cours que nous avons eu (pas de choix) étaient avec d''autre étudiants en mobilité donc quasiment aucune rencontre avec les québécois lors des créneaux de cours.", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Non"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "details": "Soirées organisées assez fréquemment mais très peu de places disponibles par rapport au nombre d''étudiants, c''est dommage...", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Suivre le compte cc.uqac sur instagram qui permet d''être au courant assez vite des événements organisés"}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "4", "details": "Pas de différence faite avec les autres", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Nous sommes allés à Tadoussac un jour où il y avait une fête traditionnelle locale, on peut l''apparenter à nos fêtes de villages, l''ambiance était géniale"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Les restaurants (fast-food compris) ferment à 19h30, 21h pour le plus tardif à Chicoutimi, les québécois mangent très tôt !"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "4", "details": "Hormis le point précédent, qui était embêtant lorsqu''on sortait du cours d''anglais terminant à 22h.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "La poutine"}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Ne pas se prendre la tête"}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "1100"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "3", "details": "Les sites proposés par Alice Fleury sont absolument inutiles, les appartements sont très chers, chercher un logement sur airbnb est une bonne solution mais il est recommandé de prendre un logement avec d''autres personnes sinon le prix est assez élevé", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Bon rapport qualité prix, environ 350 par personne à 3 dans le logement"}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "details": "Logement avec vue sur la baie de Saguenay (magnifique), les installations fonctionnaient très bien. La machine à laver est tombée en panne, le propriétaire nous en a installé une neuve dans les heures qui ont suivi !", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "Cuisine bien équipée, Télévision, internet bon débit", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "details": "bus à environ 5min de marche", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "details": "zone commerciale à 5min en voiture (20min à pieds), bar à 1min à pieds ;)", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Quartier plutôt aisé, beaucoup de retraités, très calme", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Ce logement est nommé \"Logement du fjord\" sur airbnb, l''hôte est Eric, sans doute le meilleur hôte que j''ai rencontré en airbnb."}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1000", "details": "Compliqué à estimer car nous avons pris un logement assez cher quand même et nous avons loué une voiture sur toute la durée du séjour"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Entre 100 et 200 CAD (70-140€) de courses par semaine pour avoir une alimentation équilibrée, fruits et légumes assez coûteux"}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites.", "value": "Prix des bars et restos un peu plus cher qu''en France mais pas choquant. La meilleure activité pour un petit budget est d''aller voir un match de hockey pour 20 CAD (~14€)"}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Très élevé"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "Ne pas prendre d''abonnement sur place, c''est un intérêt supplémentaire de prendre un airbnb d''ailleurs. Pour la téléphonie, un des forfaits les moins chers que j''avais trouvé s''élevait à 50€ pour 10Go d''internet."}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Bas"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Nous n''avons pas pris souvent les transport mais le prix était abordable. De plus, l''UQAC propose un abonnement au bus pour les étudiants mais je ne connais pas le prix. L''essence est très peu chère comparé à la France"}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Elevé"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Arrêter de mettre des cours obligatoires qui ne sont pas adaptés, prendre en compte les retours des étudiants. J''ai dit dans mon retour à Alice Fleury que le cours de Machine Learning n''était pas adapté, elle m''a assuré prendre en compte ma remarque mais le cours est resté obligatoire l''année suivante..."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Cette expérience m''a donné envie de voyager et m''a permis de découvrir un nouveau pays et un nouveau continent"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Toronto, Québec, Montréal, New-York, Le hockey, la poutine, les bars"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "Aucun, honnêtement les cours sont là pour faire de la figuration, c''est clairement un voyage touristique. Il suffit de passer 2-3h par semaine à travailler sérieusement les projets à rendre et la mobilité est validée. Les évaluations sont faites en distanciel avec \"Interdiction de communiquer\" et \"obligation de se placer dans des pièces séparées si colocation\". Il n''existe bien sûr aucun moyen de vérifier ça et les partiels sont donc effectués en groupe"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": ["https://cdn.trav3il.fr/feedback/feedback_3/DSC00580.JPG", "https://cdn.trav3il.fr/feedback/feedback_3/00004.mp4", "https://cdn.trav3il.fr/feedback/feedback_3/DSC00409.JPG", "https://cdn.trav3il.fr/feedback/feedback_3/DSC00400.JPG", "https://cdn.trav3il.fr/feedback/feedback_3/DSC00708.JPG", "https://cdn.trav3il.fr/feedback/feedback_3/DSC00682.JPG"]}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-21', 'UQAC', 2023, 'Chicoutimi', 'Canada', 'alternant', true, 'Elisa', 'Rousseau', 'elisa.rousseau0@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (5, '[{"questions": [{"type": "text", "label": "Nom", "value": "Slamnia"}, {"type": "text", "label": "Prénom", "value": "Kylan"}, {"type": "email", "label": "Email", "value": null}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Non"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "22"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Gatineau"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQO"}, {"type": "select-one", "label": "Type de programme", "value": "Echange bilatéral"}, {"type": "date", "label": "Date de début", "value": "2024-09-02"}, {"type": "date", "label": "Date de fin", "value": "2024-12-17"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1200"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "6 mois"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Oui", "details": "Paiement de l''AVE"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Prévenir la banque de la mobilité pour ne pas se faire bloquer ses comptes"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Pour simplifier les démarches, mieux vaut prendre un pack qui regroupe complémentaire santé, assurance rapatriement et assurance responsabilité civile"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Oui", "details": "Il faut payer l''AVE canadien"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "J''ai changé de forfait avec un minimum de données pour la France pour qu''il soit moins cher, avec une option internationale de 5€ pour 20Go/mois au Canada"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "Cybersécurité comportementale"}, "Avis du cours": {"type": "textarea", "value": "C''est un cours facile. Permet de s''assurer une bonne note sans trop se fatiguer."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours de première année, pas très instructif pour quelqu''un qui s''y connait un peu en cybersécurité. Parle des vulnérabilités humaines, organisationnelles et culturelles dans les entreprises. Aborde les techniques d''attaques basées sur la manipulation d''autrui (ingénierie sociale)."}}, {"Nom du cours": {"type": "text", "value": "Forensique numérique"}, "Avis du cours": {"type": "textarea", "value": "Sur le papier, le cours est super intéressant. Le problème c''est la prof qui ne s''y connait pas (et ça se voit). Le plus intéressant c''est la partie pratique, ça permet de découvrir des outils et de techniques de forensique."}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Notions de cyberenquête, informatique judiciaire, collecte de preuves numériques, droit canadien en informatique, etc."}}, {"Nom du cours": {"type": "text", "value": "Application de l''intelligence artificielle en cybersécurité"}, "Avis du cours": {"type": "textarea", "value": "Cours très intéressant, si vous avez des connaissances en IA et/ou en cybersécurité, c''est un cours accessible. Pas besoin d''être bon en maths, simplement de comprendre les notions. La prof rend les notions super compréhensibles. Je recommande fortement."}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Aborde les notions d''IA appliquée à la cybersécurité et de sécurité des modèles d''IA. Apprentissage de différents algorithmes pour résoudre des problèmes de cybersécurité (détection d''intrusion, de phishing, de spams, d''attaques, etc.)"}}, {"Nom du cours": {"type": "text", "value": "Fondement de l''IA"}, "Avis du cours": {"type": "textarea", "value": "C''est la première fois que le prof donnait le cours, il était un peu trop en improvisation à mon goût. C''est assez particulier comme matière, mais on apprend quand même des notions intéressantes. Pas vraiment utile pour suivre d''autres cours d''IA, donc ne pas se fier au titre."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Notions d''agent intelligent, de recherche, de logique (formelle et probabiliste), d''apprentissage."}}, {"Nom du cours": {"type": "text", "value": "Management de projet"}, "Avis du cours": {"type": "textarea", "value": "Cours obligatoire. Le contenu n''est pas beaucoup plus instructif que la gestion de projet de 3iL, mais le cours n''est pas pénible à suivre."}, "Notez ce cours": {"type": "rating", "value": "3", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Structures d''organisations, méthodes historiques de management, outils de management, etc."}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "17.5"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "4", "details": "Il y a beaucoup d''étudiants français à l''UQO. Donc compliqué de se mêler à des québecois", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Journée de présentation de l''UQO. Soirée d''intégration."}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Vous allez rencontrer d''autres étudiants de 3iL (des autres campus). Donc facile de faire de nouvelles connaissances. Pour le reste, essayez de participer à quelques évènements de l''UQO."}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Personne ne vous fera remarquer que vous êtes français. J''ai trouvé l''accueil naturel, comme si je vivais au Québec depuis toujours. Après , n''hésitez pas à poser des questions aux gens sur des choses que vous ne comprenez pas.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Des matchs de hockey principalement. Il y a la NHL à Ottawa !"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Non"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "La poutine, le sirop d''érable, les queues de castor (pâtisserie). Ne vous attendez pas à avoir une grande diversité comme en France par contre (RIP le fromage)."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": null}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Oui", "details": "Internet est votre ami. Faites des recherches dès que quelque chose vous intrigue."}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "600"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "3", "details": "On a utilisé Airbnb. Prenez-vous y dès que vous avez les résultats des vœux. Si vous êtes minimum 3, vous pouvez louer une maison (c''est le mieux pour le confort). Il y a une crise de l''immobilier en ce moment au Canada (2024), donc les loyers s''envolent.", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Le prix par personne est très correcte pour une maison à Gatineau."}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "5", "details": "Toute équipée.", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "Toute équipée.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "4", "details": "On avait un arrêt de bus à 5 minutes à pieds. Pas de métro à Gatineau.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "4", "details": "Walmart à 10 minutes à pieds.", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Quartier résidentiel calme.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Uniquement s''y prendre le plus tôt possible (juste après les vœux). Essayez de faire une colocation pour plus de choix."}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1300"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": null}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Elevé"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": null}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Modéré"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": null}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Très élevé"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Prenez l''abonnement trimestriel étudiant à la STO. Pour l''avoir il faut être inscrit à l''UQO. Donc mon conseil est que si vous arrivez avant la rentrée, allez au bureau du registraire pour vous inscrire. Et dès que vous êtes inscrits à vos cours (il faut avoir son emploi du temps), allez à la STO. La STO est débordée pendant les 2 semaines après la rentrée, donc si vous voulez votre abonnement, faites le tôt."}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Elevé"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": null}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": null}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Voyager dans le Canada, essayez de vous libérer 1 ou 2 jours de cours par semaine en vous inscrivant aux cours. Vous êtes aussi là pour visiter le pays, pas que pour le diplôme."}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": null}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": []}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-22', 'UQO', 2024, 'Gatineau', 'Canada', 'alternant', false, null, null, null);
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (4, '[{"questions": [{"type": "text", "label": "Nom", "value": "GARNIER"}, {"type": "text", "label": "Prénom", "value": "Marius"}, {"type": "email", "label": "Email", "value": "garnierm@3il.fr"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "22"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Chicoutimi"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQAC"}, {"type": "select-one", "label": "Type de programme", "value": "Cohorte"}, {"type": "date", "label": "Date de début", "value": "2024-08-20"}, {"type": "date", "label": "Date de fin", "value": "2024-12-12"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1000"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Oui"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Oui", "details": "idk"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Non"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "carte gold a debit différée (credit agricole) Avec cette carte bleue on peut tout payer comme en France"}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Oui", "details": "Inscription à la RAMQ ( CPAM du Quebec)"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Assurance complémentaire prise pour le voyage (groupama)"}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Red by sfr (le forfait a 20gb canada + etats unis)"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "BDD / Big Data / Intelligence d''affaires / anglais / Application mobile"}, "Avis du cours": {"type": "textarea", "value": "Tous les sont supers !"}, "Notez ce cours": {"type": "rating", "value": "5", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Tous les cours sont composées essentiellement de projet ainsi que des partiels"}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "5", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "12"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Soirées organisés par l''UQAC pour le début de la session d''automne"}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Non"}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "5", "details": "Super vie sociale étudiante", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "Faire les soirée organisés par l''UQAC"}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "5", "details": "Super accueil de la population québécoise", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "FestiCam, participer aux matchs de hockey des saguenéens de Chicoutimi"}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Hockey et baseball"}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "poutine"}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Non"}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": null}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "600"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "5", "details": "Location d''une maison via Airbnb à 10min en voiture de l''UQAC en colocation à 3", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "Assez cher mais honnete pour la taille de la maison louée"}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "4", "details": "tout etait parfait sauf les cuisine (equipement leger)", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "5", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Airbnb"}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "1000", "details": "le budget mensuel varie en fonction des mois car on peut y inclure egalement les différents voyages réalisés lors de la mobilité"}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": null}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites", "value": null}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Modéré"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": null}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": null}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Elevé"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Rien a modifier."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Superbe expérience qui m''a permis de découvrir un pays tout en ayant des cours en parallèle, super !"}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Tous était super !"}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "La selection des cours avant la mobilité n''est pas respectée car nous sommes dans une cohorte -> tous les memebres de 3il suivent donc les mêmes cours"}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": ["https://trav3il.b-cdn.net/feedback/feedback_4/54126005620_82633e1470_o.jpg", "https://trav3il.b-cdn.net/feedback/feedback_4/cm-chat-media-video-1c3160369-7043-4d5f-93c3-95d9b175663a109460.mov", "https://trav3il.b-cdn.net/feedback/feedback_4/IMG_1797.jpg", "https://trav3il.b-cdn.net/feedback/feedback_4/IMG_1818.jpg", "https://trav3il.b-cdn.net/feedback/feedback_4/IMG_3860.jpg", "https://trav3il.b-cdn.net/feedback/feedback_4/IMG_7491.jpg", "https://trav3il.b-cdn.net/feedback/feedback_4/IMG_7792.jpg", "https://trav3il.b-cdn.net/feedback/feedback_4/IMG_7912.jpg"]}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-21', 'UQAC', 2024, 'Chicoutimi', 'Canada', 'alternant', true, 'Pierre', 'Fontaine', 'fontainep@gmail.com');
INSERT INTO public.feedbacks (id, form_data, is_visible, submission_date, school, year, city, country, user_type, is_contact, firstname, lastname, email) VALUES (2, '[{"questions": [{"type": "text", "label": "Nom", "value": "Ruel"}, {"type": "text", "label": "Prénom", "value": "Alexis"}, {"type": "email", "label": "Email", "value": "alexis.rue@protonmail.com"}, {"type": "checkbox", "label": "En cochant cette case, j''accepte d''être contacté(e) par des étudiants pour partager des informations et des retours d''expérience.", "value": "Oui"}, {"type": "select-one", "label": "Quel était votre âge au moment de la mobilité ?", "value": "22"}, {"type": "select-one", "label": "Campus 3iL", "value": "Rodez"}, {"type": "select-one", "label": "Quel était votre statut étudiant ?", "value": "Alternant"}], "stepLabel": "Étape 1: Informations Personnelles 👤", "stepVisibility": "0"}, {"questions": [{"type": "text", "label": "Pays", "value": "Canada"}, {"type": "text", "label": "Ville", "value": "Gatineau"}, {"type": "text", "label": "Établissement d''accueil", "value": "UQO"}, {"type": "select-one", "label": "Type de programme", "value": "Echange bilatéral"}, {"type": "date", "label": "Date de début", "value": "2023-08-25"}, {"type": "date", "label": "Date de fin", "value": "2023-12-20"}, {"type": "select-one", "label": "Moyen de transport pour vous rendre à votre destination", "value": "Avion"}, {"type": "number", "label": "Prix aller-retour (€)", "value": "1000"}, {"type": "select-one", "label": "Langue d''enseignement", "value": "Français"}], "stepLabel": "Étape 2: Informations sur la mobilité 🗺️", "stepVisibility": "1"}, {"questions": [{"type": "select-one", "label": "Un passeport est-il obligatoire ?", "value": "Non"}, {"type": "select-one", "label": "Une durée minimum restante de validité est-elle nécessaire ?", "value": "Non"}, {"type": "select-one", "label": "Un visa est-il obligatoire ?", "value": "Oui", "details": "Visa pas obligatoire pour moins de 6 mois mais autorisation de voyage électronique (AVE) obligatoire dans tous les cas (on vous la demande pour prendre l''avion de toute façon), démarche rapide et vraiment pas compliqué"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches pour être autoriser à conduire (permis de conduire)", "value": "Oui", "details": "Demande de permis international obligatoire, à faire le plus tôt car un peu lent"}, {"type": "select-one", "label": "Y''a-t-il des vaccinations obligatoires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance spécifique logement ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû réaliser des démarches particulières pour votre carte bancaire ?", "value": "Oui", "details": "Je conseille de s''informer sur les offres des banques sur les taux de change pour ne pas payer un certain % sur chaque transaction par carte. (sinon passer par des banques comme revolut ou n26 mais pas fiable à 100% en cas de problème)."}, {"type": "select-one", "label": "Si alternant,  avez-vous eu une mise en veille de votre contrat d''apprentissage ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous bénéficier d''aides financières ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû souscrire à une assurance de santé locale ?", "value": "Oui", "details": "Inscription à la RAMQ"}, {"type": "select-one", "label": "Avez-vous souscris une assurance complémentaire de rapatriement ?", "value": "Oui", "details": "Il me semble que 3iL la demande dans tous les cas donc pas le choix, perso j''ai pris april international, l''assurance séjour à l''étranger."}, {"type": "select-one", "label": "Avez-vous enregistrer votre séjour sur le site du gouvernement français (Fil d''Ariane)?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous dû vous enregistrer auprès des autorités locales ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous souscrit un abonnement de téléphonie mobile spécifique ?", "value": "Oui", "details": "Option étranger avec 34Go chez redbysfr"}], "stepLabel": "Étape 3: Détails des Démarches Administratives 📋", "stepVisibility": "1"}, {"questions": [{"type": "dynamic", "label": "Cours suivis", "value": [{"Nom du cours": {"type": "text", "value": "CYB1073 - Cybersécurité Comportementale"}, "Avis du cours": {"type": "textarea", "value": "Vraiment pas intéressant quand on a déjà les notions de base, cours en full visio donc possible de ne pas suivre vu la trivialité du cours."}, "Notez ce cours": {"type": "rating", "value": "1", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Notions de base sur la cybersécurité, QCM en ligne, très bonne note garantie à 100% (si vous avez le même prof que moi)."}}, {"Nom du cours": {"type": "text", "value": "INF6153 - Systèmes de contrôle d''accès aux données"}, "Avis du cours": {"type": "textarea", "value": "Excellent cours, utilise pour plus tard peu importe votre spécialité (dev, réseau, web, etc...)"}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Rapport + exposé pour la fin du semestre avec bibliographie, assez exigeant aux premiers abords mais possibilité d''avoir une très bonne note en étant sérieux."}}, {"Nom du cours": {"type": "text", "value": "INF6233 - Sécurité informatique et méthodes formelles"}, "Avis du cours": {"type": "textarea", "value": "Cours d''alien de très loin le plus dur de l''UQO, il faut bien suivre tous les cours sinon c''est impossible de s''en remettre mais excellent professeur et super intéressant. Pour l''examen, difficulté ok pour avoir la moyenne par contre si vous visez le 20 n''y pensez même pas."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Méthodes d''évaluation du niveau de sécurité d''un système, utilisation du langage formel. Examen sur feuille en fin de semestre et mini examen toutes les 2 semaines environ."}}, {"Nom du cours": {"type": "text", "value": "INF6343 - Intelligence Artificielle Distribuée"}, "Avis du cours": {"type": "textarea", "value": "Très cool, également un des meilleurs cours, pas hyper compliqué et vraiment prenant donc je recommande."}, "Notez ce cours": {"type": "rating", "value": "4", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Concepts de base de l''IA distribuée, théorie des jeux, projet de dev de sa propre IA distribuée + exposé."}}, {"Nom du cours": {"type": "text", "value": "MGP7111A - Project Management and its Environment"}, "Avis du cours": {"type": "textarea", "value": "Le cours serait ok si on revoyait pas pour la 10ème fois les mêmes choses, surtout que ce cours est le seul qui est imposé par 3iL alors que c''est clairement le seul qui n''apporte rien donc qui devrait même être interdit de prendre tant il est inutile."}, "Notez ce cours": {"type": "rating", "value": "2", "option": "note"}, "Description du cours": {"type": "textarea", "value": "Cours de gestion de projet en anglais, les mêmes concepts qu''on apprend depuis 5 ans, examen sous forme de QCM sur internet où il faut juste connaitre par coeur."}}], "questionId": "31"}, {"type": "rating", "label": "Évaluation de l''enseignement", "value": "4", "ratingOption": "note"}, {"type": "number", "label": "Heures hebdomadaires de cours", "value": "15"}, {"type": "select-one", "label": "Avez-vous reçu un soutien académique ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la facilité d''intégration académique", "value": "4", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous rencontré des difficultés scolaires ?", "value": "Non"}, {"type": "select-one", "label": "Avez-vous validé votre mobilité ?", "value": "Oui"}], "stepLabel": "Étape 4: Aspects Académiques 🏫", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Facilité d''intégration avec les étudiants locaux et internationaux", "value": "5", "details": "Beaucoup plus d''interactions entre les internationaux qu''avec les québécois. Mais vu qu''il y a énormément d''internationaux et surtout de français, pas un problème + les québécois sont au lit à 22h, je rigole pas c''est une folie les mecs dorment 12h par jour ohoh réveillez-vous les mecs !!!", "ratingOption": "note"}, {"type": "select-one", "label": "Activités d''accueil pour les étudiants étrangers", "value": "Oui", "details": "Soirées organisées par les associations de l''UQO, au bar de l''université, dans les bars, etc. Niveau communication par contre, ce n''est pas trop ça, il faut bien regarder sur les réseaux pour ne pas louper les événements."}, {"type": "select-one", "label": "Possibilité de participer à des clubs et associations étudiantes", "value": "Oui", "details": "."}, {"type": "select-one", "label": "Avez-vous contribuer à un club ou une association étudiante ?", "value": "Non"}, {"type": "rating", "label": "Évaluation de la vie sociale étudiante", "value": "4", "ratingOption": "note"}, {"type": "textarea", "label": "Vos conseils d''intégration pour les futurs étudiants", "value": "N''hésitez pas à sortir et à parler à des gens même si vous êtes timides d''habitude, l''ambiance est vraiment différente là-bas et c''est beaucoup plus chaleureux qu''en France même si vous parlez avec des français, normalement vous aurez aucun problème."}], "stepLabel": "Étape 5: Vie Sociale et Intégration 👥", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Comment évalueriez-vous l''accueil des habitants envers les étudiants étrangers ?", "value": "3", "details": "Très rare de croiser des habitants locaux, les interactions se font surtout avec d''autres étudiants. Par contre, les rares interactions avec des locaux sont vraiment cools, les gens sont très humains et parlent beaucoup.", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous participé à des activités ou événements culturels locaux ?", "value": "Oui", "details": "Match de hockey, de football américain, marché de Noël d''Ottawa, festival de montgolfière. Faites le + de trucs possibles, c''est vraiment des choses cools qu''on voit jamais."}, {"type": "select-one", "label": "Avez-vous trouvé certaines coutumes ou traditions locales particulièrement intéressantes ou surprenantes ?", "value": "Oui", "details": "Le Panda Games, c''est un match de football américain entre les deux grosses universités d''Ottawa, et c''est vraiment une ambiance de fou. Le marché de Noël d''Ottawa, c''est vraiment comme dans les films."}, {"type": "rating", "label": "Comment s’est passée votre adaptation aux habitudes de vie locales ?", "value": "5", "ratingOption": "note"}, {"type": "select-one", "label": "Avez-vous découvert des plats ou des spécialités locales ?", "value": "Oui", "details": "La poutine, les queues de castor."}, {"type": "select-one", "label": "Avez-vous remarqué des différences sociales ou religieuses importantes ?", "value": "Oui", "details": "Le truc le plus flagrant, c''est l''impression qu''il ne va rien t''arriver, même dans les toutes petites villes de France, ce n''est pas comme ça. Là-bas, les gens ne ferment même pas leurs portes à clé, tu peux te balader à 3h du matin, il ne t''arrivera jamais rien."}, {"type": "textarea", "label": "Quels conseils donneriez-vous pour une adaptation culturelle réussie ?", "value": "Faire le + d''activités possibles mais à part ça, ça ne change pas trop de la France."}, {"type": "select-one", "label": "Y a-t-il des ressources qui vous ont aidé à comprendre la culture locale ?", "value": "Non"}], "stepLabel": "Étape 6: Culture et Coutumes Locales 🏺", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Coût mensuel du logement", "value": "450"}, {"type": "select-one", "label": "Type de logement", "value": "Colocation"}, {"type": "rating", "label": "Facilité de trouver un logement", "value": "4", "details": "Pas trop compliqué de trouver sur Airbnb.", "ratingOption": "note"}, {"type": "textarea", "label": "Comment évalueriez vous le coût ? Bon rapport qualité/prix ?", "value": "C''est assez cher comparé à d''autres pays mais le coût de la vie compense quand même pas mal."}, {"type": "rating", "label": "Qualité du logement et des installations", "value": "4", "ratingOption": "note"}, {"type": "rating", "label": "Confort et équipements du logement", "value": "5", "details": "Tous les équipements qu''on peut espérer avoir (four, micro-onde, congélateur, internet, télé, ...).", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des transports", "value": "4", "details": "5-10 minutes à pieds des transports qui amènent directement partout où on veut (centre commercial au centre d''Ottawa, grandes surfaces de Gatineau, ...). 50 mètres à pieds d''un des deux bâtiments de l''université et 15 minutes à pieds de l''autre.", "ratingOption": "note"}, {"type": "rating", "label": "Proximité des commerces", "value": "3", "details": "Pas trop de restaurant à part tout ce qui est fast-food. Sinon bon accès aux supermarchés, même si sans voiture tout faire à pied devient compliqué au bout d''un moment vu qu''il fait -10°C. Mais les courses se font très facilement sur UberEats ou autre, c''est quelque chose de très répandu là-bas et qui change la vie.", "ratingOption": "note"}, {"type": "rating", "label": "Sécurité du logement et du quartier", "value": "5", "details": "Quartier calme et vraiment tranquille niveau sécurité, on peut même laisser la porte ouverte tellement c''est serein.", "ratingOption": "note"}, {"type": "textarea", "label": "Conseils ou recommandations pour trouver un logement similaire", "value": "Beaucoup d''Airbnb sont justement dédiés aux étudiants qui restent 4 mois pour le semestre d''automne donc vraiment facile de trouver et se mettre d''accord avec le proprio sur la durée du séjour. Sinon possibilité d''avoir une chambre universitaire en coloc de 2, 4 ou 6 en faisant une demande sur le site de l''UQO."}], "stepLabel": "Étape 7: Logement 🏠", "stepVisibility": "1"}, {"questions": [{"type": "number", "label": "Budget mensuel total (estimation en €)", "value": "800", "details": "800€ tu vis vraiment bien. Je pense qu''à partir de 500€ par mois tu peux vivre (hors soirées et sorties où il faut rajouter 100 à 300 par mois pour être tranquille)."}, {"type": "select-one", "label": "Coût des courses alimentaires et des repas", "value": "Modéré"}, {"type": "textarea", "label": "Exemple de dépenses alimentaires, bons plans, etc.", "value": "Les courses sont un peu moins chères qu''en France et les fast-foods aussi. Par contre, les restaurants peuvent vite monter avec le système de tips (pas obligatoire cela dit)."}, {"type": "select-one", "label": "Coût des activités de loisirs et sorties", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions d''activités abordables ou gratuites.", "value": "Week-end dans une autre ville (Montréal, Toronto, Québec) ~ 200€. Match de hockey ou de football américain ~ 30€. Plein d''événements et festivals sont gratuits."}, {"type": "select-one", "label": "Coût des services (internet, téléphone, etc.)", "value": "Elevé"}, {"type": "textarea", "label": "Détails sur les abonnements internet, téléphonie, etc.", "value": "Prendre un abonnement en France qui fait international."}, {"type": "select-one", "label": "Coût des transports (prix des tickets, abonnement étudiant)", "value": "Modéré"}, {"type": "textarea", "label": "Suggestions pour réduire les coûts de transport", "value": "Pas excessif si on prend un abonnement mais pas sûr que ce soit rentable."}, {"type": "select-one", "label": "Évaluation du coût de la vie par rapport au pays d''origine", "value": "Modéré"}], "stepLabel": "Étape 8: Coût de la Vie 💶", "stepVisibility": "1"}, {"questions": [{"type": "rating", "label": "Satisfaction générale de l’expérience", "value": "5", "ratingOption": "note"}, {"type": "textarea", "label": "Recommandations pour améliorer le programme de mobilité", "value": "Plus de communication sur l''administratif de la part de 3iL (par exemple, sur les OPCO qui peuvent financer vos mobilités si votre contrat est mis en veille à hauteur de presque 2000€, sur le système de santé et la RAMQ, sur l''inscription et le choix des cours...)."}, {"type": "textarea", "label": "Impact de l''expérience sur vos perspectives académiques et personnelles", "value": "Pas d''impact à proprement parler mais très beau souvenir."}, {"type": "textarea", "label": "Points forts de votre expérience", "value": "Découvrir une culture différente, rencontrer des gens, les cours sont dans l''ensemble assez cools."}, {"type": "textarea", "label": "Défis ou difficultés rencontrées", "value": "Pas vraiment de difficultés, peut-être financièrement ça peut être compliqué si le contrat est mis en veille."}, {"type": "select-one", "label": "Recommanderiez-vous cette mobilité à d''autres étudiants ?", "value": "Absolument"}], "stepLabel": "Étape 9: Évaluation Générale et Suggestions 💯", "stepVisibility": "1"}, {"questions": [{"type": "file", "label": "Si vous souhaitez partager des photos/vidéos de votre mobilité", "value": ["https://trav3il.b-cdn.net/feedback/feedback_2/33A31249-C907-451F-BB8A-3082E38676B8.jpg", "https://trav3il.b-cdn.net/feedback/feedback_2/810485BF-D761-4F35-94F1-664BDF69B808.jpg", "https://trav3il.b-cdn.net/feedback/feedback_2/886F675C-1801-423A-AF1A-B701EC500EBA.jpg", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_0005.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_0048.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_0144.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5055.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5059.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5059.MP4", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5754.MP4", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5792.JPG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5817.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_5942.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_6358.PNG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_6587.JPG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_6861.JPG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_6898.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_7276.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_7317.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_7393.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_7728.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_7854.JPG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_8089.JPEG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_8105.JPG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_8125.JPG", "https://trav3il.b-cdn.net/feedback/feedback_2/IMG_8137.JPG"]}], "stepLabel": "Étape 10: Photos et Vidéos 🖼️", "stepVisibility": "1"}]', true, '2024-11-14', 'UQO', 2023, 'Gatineau', 'Canada', 'alternant', true, 'Clara', 'Mercier', 'clara.mercier@protonmail.com');
